import time
import grpc
import auth_data_pb2
import auth_data_pb2_grpc

_USERS = {
    "alice": "password123",
    "bob": "secret456",
}

_TOKENS = {}

_DATA = {
    "1": "Resource data for item 1",
    "2": "Resource data for item 2",
    "3": "Resource data for item 3",
}

def _generate_token(username: str) -> str:
    return f"token-{username}-{int(time.time())}"

def _get_username_from_token(token: str):
    return _TOKENS.get(token)

class AuthService(auth_data_pb2_grpc.AuthServiceServicer):
    def Login(self, request, context):
        if _USERS.get(request.username) == request.password:
            token = _generate_token(request.username)
            _TOKENS[token] = request.username
            return auth_data_pb2.LoginResponse(
                success=True,
                token=token,
                message="Login successful",
            )
        return auth_data_pb2.LoginResponse(
            success=False,
            token="",
            message="Invalid credentials",
        )

    def ValidateToken(self, request, context):
        username = _get_username_from_token(request.token)
        return auth_data_pb2.ValidateTokenResponse(
            valid=username is not None,
            username=username or "",
        )

class DataService(auth_data_pb2_grpc.DataServiceServicer):
    def GetData(self, request, context):
        username = _get_username_from_token(request.token)
        if not username:
            return auth_data_pb2.GetDataResponse(
                success=False,
                resource_id=request.resource_id,
                data="",
                message="Unauthorized: invalid token",
            )

        value = _DATA.get(request.resource_id)
        if value is None:
            return auth_data_pb2.GetDataResponse(
                success=False,
                resource_id=request.resource_id,
                data="",
                message="Resource not found",
            )

        return auth_data_pb2.GetDataResponse(
            success=True,
            resource_id=request.resource_id,
            data=f"{value} (requested by {username})",
            message="Data retrieved successfully",
        )

